#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin — Created: 2026-04-27
# /ork:dev stop — tear down the lab stack in reverse boot order.

set -euo pipefail

PROJECT_DIR="${CLAUDE_PROJECT_DIR:-$(pwd)}"
STATE_FILE="${PROJECT_DIR}/.claude/state/dev-stack.json"

if [[ ! -f "${STATE_FILE}" ]]; then
  echo "ork:dev — no state file found, nothing to stop." >&2
  exit 0
fi

# Reverse boot order: agent-browser → dev server → emulate → portless
session=$(python3 -c "import json; s=json.load(open('${STATE_FILE}')); print(s['processes'].get('agentBrowser', {}).get('sessionName', ''))" 2>/dev/null || echo "")
dev_pid=$(python3 -c "import json; s=json.load(open('${STATE_FILE}')); print(s['processes'].get('devServer', {}).get('pid', 0))" 2>/dev/null || echo 0)
emu_pid=$(python3 -c "import json; s=json.load(open('${STATE_FILE}')); print(s['processes'].get('emulate', {}).get('pid', 0))" 2>/dev/null || echo 0)
sub=$(python3 -c "import json; s=json.load(open('${STATE_FILE}')); print(s.get('subdomain', ''))" 2>/dev/null || echo "")

echo "ork:dev — sending SIGTERM in reverse boot order…" >&2

# 1. agent-browser session
if [[ -n "${session}" ]]; then
  agent-browser session stop --name "${session}" 2>/dev/null && echo "  ✓ agent-browser session stopped" >&2 || echo "  ⚠ agent-browser session not running" >&2
fi

# 2. dev server (SIGTERM, then SIGKILL after 5s)
if [[ "${dev_pid}" != "0" ]] && kill -0 "${dev_pid}" 2>/dev/null; then
  kill -TERM "${dev_pid}" 2>/dev/null || true
  for _ in 1 2 3 4 5; do kill -0 "${dev_pid}" 2>/dev/null || break; sleep 1; done
  kill -0 "${dev_pid}" 2>/dev/null && kill -KILL "${dev_pid}" 2>/dev/null || true
  echo "  ✓ dev server (pid ${dev_pid}) stopped" >&2
fi

# 3. emulate
if [[ "${emu_pid}" != "0" ]] && kill -0 "${emu_pid}" 2>/dev/null; then
  kill -TERM "${emu_pid}" 2>/dev/null || true
  echo "  ✓ emulate (pid ${emu_pid}) stopped" >&2
fi

# 4. portless
if [[ -n "${sub}" ]]; then
  portless stop --domain "${sub}" 2>/dev/null && echo "  ✓ portless ${sub} stopped" >&2 || echo "  ⚠ portless ${sub} not running" >&2
fi

rm -f "${STATE_FILE}"
echo "Cleared ${STATE_FILE}" >&2
